@code {
    private Order _order = new();
    private int _step = 1;

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private void GoToPayment()
    {
        _step = 2;
    }

    private void GoBackToShipping()
    {
        _step = 1;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@if (_step == 1)
{
    <ShippingStep Shipping="_order.Shipping" OnNext="GoToPayment" />
}
else
{
    <PaymentStep Payment="_order.Payment" OnBack="GoBackToShipping" OnPlaceOrder="PlaceOrder" />
}

@inject IAddressValidator AddressValidator
@implements IDisposable

<h3>Shipping Information</h3>

<div class="form-group">
    <label>Name</label>
    <input @bind="Shipping.Name" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label>Address</label>
    <input @bind="Shipping.Address" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label>City</label>
    <input @bind="Shipping.City" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label>Zip Code</label>
    <input @bind="Shipping.ZipCode" disabled="@_isValidating" />
</div>

@if (_validationError is not null)
{
    <div class="validation-error">@_validationError</div>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner"></span>
        <span>Validating...</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _validationError;

    [Parameter]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task ValidateAndProceed()
    {
        // Cancel any in-flight validation
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;
        _validationError = null;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — no action needed
        }
        finally
        {
            if (!token.IsCancellationRequested)
            {
                _isValidating = false;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

